import React from "react";
import { useParams, Link } from "react-router-dom";
import "./BookingConfirmation.css";

const listings = [
  {
    id: 1,
    name: "Luxury Beach Villa",
    image: "https://images.pexels.com/photos/2102587/pexels-photo-2102587.jpeg",
  },
  {
    id: 2,
    name: "Cozy Mountain Cabin",
    image: "https://images.pexels.com/photos/277572/pexels-photo-277572.jpeg",
  },
  {
    id: 3,
    name: "Modern City Apartment",
    image: "https://images.pexels.com/photos/271624/pexels-photo-271624.jpeg",
  },
  {
    id: 4,
    name: "Traditional Heritage Home",
    image: "https://images.pexels.com/photos/259588/pexels-photo-259588.jpeg",
  },
];

// Added experiences list
const experiences = [
  {
    id: 101,
    name: "Skydiving Adventure",
    image:
      "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?fit=crop&w=800&q=80",
  },
  {
    id: 102,
    name: "Mountain Hiking",
    image:
      "https://images.unsplash.com/photo-1501785888041-af3ef285b470?fit=crop&w=800&q=80",
  },
  {
    id: 103,
    name: "Scuba Diving",
    image:
      "https://images.unsplash.com/photo-1470770903676-69b98201ea1c?fit=crop&w=800&q=80",
  },
  {
    id: 104,
    name: "Desert Safari",
    image:
      "https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?fit=crop&w=800&q=80",
  },
  {
    id: 105,
    name: "Camping Under Stars",
    image:
      "https://images.unsplash.com/photo-1506744038136-46273834b3fb?fit=crop&w=800&q=80",
  },
];

export default function BookingConfirmation() {
  const { id } = useParams();
  const bookingId = Number(id);

  // Search in both lists
  const booking =
    listings.find((home) => home.id === bookingId) ||
    experiences.find((exp) => exp.id === bookingId);

  if (!booking) {
    return <h2>Booking not found.</h2>;
  }

  return (
    <div className="booking-page">
      <h1>Booking Confirmed 🎉</h1>
      <div className="booking-card">
        <img src={booking.image} alt={booking.name} />
        <h2>{booking.name}</h2>
        <p>Your booking has been successfully confirmed! 🏡</p>
        <Link to="/">
          <button className="back-home-btn">Back to Home</button>
        </Link>
      </div>
    </div>
  );
}
